const itens = $input.all();
if (itens.length === 0) return [{ json: { status: "sem_dados", mensagem: "Nenhuma emenda localizada." } }];

const emendas = itens.map(item => item.json);
let lista_enxuta = [];

// 1. Limpeza mantendo a granularidade máxima
for (const emenda of emendas) {
  lista_enxuta.push({
    data: emenda.DIA_PROPOSTA || "NAO_INFORMADO",
    valor: parseFloat(emenda.VALOR_REPASSE_PROPOSTA_EMENDA) || 0,
    nome_parlamentar: emenda.NOME_PARLAMENTAR || "NAO_INFORMADO",
    tipo_parlamentar: emenda.TIPO_PARLAMENTAR || "NAO_INFORMADO", // <-- COLUNA INSERIDA AQUI
    entidade_recebedora: emenda.NM_PROPONENTE || "NAO_INFORMADO",
    municipio: emenda.MUNIC_PROPONENTE || "NAO_INFORMADO",
    objeto: emenda.OBJETO_PROPOSTA || "NAO_INFORMADO",
    partido: emenda.Partido || "NAO_INFORMADO",
    orgao_superior: emenda.DESC_ORGAO_SUP || "NAO_INFORMADO",
    natureza_juridica: emenda.NATUREZA_JURIDICA || "NAO_INFORMADO"
  });
}

// 2. Conversão Dinâmica para CSV (Otimizada para Sandbox do n8n)
const chaves = Object.keys(lista_enxuta[0]);
let csv_final = chaves.join(',') + '\n';

// Uso do laço 'for' clássico para evitar estouro de memória no isolated-vm
for (let i = 0; i < lista_enxuta.length; i++) {
    let linha = lista_enxuta[i];
    let linhaArray = [];

    for (let j = 0; j < chaves.length; j++) {
        let valor = linha[chaves[j]];

        // Verifica se é string e escapa vírgulas (usando indexOf por ser mais rápido)
        if (typeof valor === 'string' && valor.indexOf(',') !== -1) {
            valor = `"${valor}"`;
        }
        linhaArray.push(valor);
    }

    csv_final += linhaArray.join(',');

    // Adiciona quebra de linha exceto no último registro
    if (i < lista_enxuta.length - 1) {
        csv_final += '\n';
    }
}

// 3. Retorna o CSV e a contagem dinâmica
return [{
    json: {
        total_linhas_dinamico: lista_enxuta.length,
        dados_csv: csv_final
    }
}];

let rawData = $input.item.json.output || $input.item.json.text;

// 1. Puxa o texto bruto das notícias
let rawNoticias = $('Formatar Notícias').first().json.texto_noticias_limpas || "";

// 2. Constrói o cabeçalho obrigatório
let fontesFormatadas = "- **Base Oficial**: Portal da Transparência\n\n";

// 3. Limpa o título do bloco bruto
let cleanNoticias = rawNoticias.replace(/=== NOTÍCIAS RECENTES \(CONTEXTO\) ===/g, "").trim();

// 4. Se tiver notícias, formata elegantemente para Markdown (Link clicável)
if (cleanNoticias.length > 0) {
    let blocos = cleanNoticias.split(/\[\d+\] /).filter(b => b.trim() !== "");

    blocos.forEach(bloco => {
        let partes = bloco.split(/\\nLink: |\nLink: /);
        if(partes.length === 2) {
            let tituloBruto = partes[0].replace("Título: ", "").replace(/\\n/g, "").replace(/\n/g, "").trim();
            let link = partes[1].replace(/\\n/g, "").replace(/\n/g, "").trim();

            let pedacos = tituloBruto.split(" - ");
            let portal = "Notícia";
            let tituloFinal = tituloBruto;

            if (pedacos.length > 1) {
                portal = pedacos.pop().trim();
                tituloFinal = pedacos.join(" - ").trim();
            }

            fontesFormatadas += `- **${portal}:** [${tituloFinal}](${link})\n\n`;
        }
    });
}

// Retorno de Segurança do JSON Automático
if (typeof rawData === 'object' && rawData !== null) {
    rawData.fontes = fontesFormatadas;
    return rawData;
}

let rawResponse = String(rawData || "");

// BLINDAGEM NUCLEAR: Usando Hexadecimal (\x60) para a crase. O motor do n8n não quebra mais.
let cleanText = rawResponse.replace(/\x60\x60\x60json/gi, "").replace(/\x60\x60\x60/g, "").trim();
cleanText = cleanText.replace(/\n/g, "\\n").replace(/\r/g, "");

let parsedResult = {};

try {
    parsedResult = JSON.parse(cleanText);
} catch (erro) {
    // Plano B de Extração
    let extract = function(key) {
        let prefix = '"' + key + '"';
        let idx = cleanText.indexOf(prefix);
        if (idx === -1) return "";

        let startVal = cleanText.indexOf('"', idx + prefix.length);
        if (startVal === -1) return "";
        startVal += 1;

        let endVal1 = cleanText.indexOf('",', startVal);
        let endVal2 = cleanText.indexOf('"}', startVal);
        let endVal = -1;

        if (endVal1 !== -1 && endVal2 !== -1) {
            endVal = Math.min(endVal1, endVal2);
        } else if (endVal1 !== -1) {
            endVal = endVal1;
        } else if (endVal2 !== -1) {
            endVal = endVal2;
        } else {
            endVal = cleanText.length;
        }

        let result = cleanText.substring(startVal, endVal);
        if (result.endsWith('"')) {
            result = result.substring(0, result.length - 1);
        }
        return result;
    };

    parsedResult = {
        output: extract("output") || "Análise processada.",
        perfil: extract("perfil") || "**Aviso:** Erro de formatação no envio, mas a análise foi feita.",
        dossie: extract("dossie") || "A análise foi interrompida pelo limite de tokens da IA. Tente fazer uma pergunta mais específica.", 
        nivel_alerta: extract("nivel_alerta") || "Monitorando"
    };
}

return {
    output: (parsedResult.output || "").replace(/\\n/g, '\n'),
    perfil: (parsedResult.perfil || "").replace(/\\n/g, '\n'),
    dossie: (parsedResult.dossie || "").replace(/\\n/g, '\n'),
    fontes: fontesFormatadas,
    nivel_alerta: parsedResult.nivel_alerta || "Monitorando"
};

// 1. Puxa a lista de notícias do nó Aggregate
const noticias_array = $input.first().json.noticias;

// 2. Cria um bloco de texto limpo para a IA ler
let texto_noticias = "=== NOTÍCIAS RECENTES (CONTEXTO) ===\n";

if (!noticias_array || noticias_array.length === 0) {
    texto_noticias += "Nenhuma notícia recente encontrada para este parlamentar sobre emendas.\n";
} else {
    noticias_array.forEach((n, index) => {
        texto_noticias += `[${index + 1}] Título: ${n.title}\nLink: ${n.link}\n\n`;
    });
}

// 3. Devolve esse bloco de texto pronto
return [{ json: { texto_noticias_limpas: texto_noticias } }];

